SELECT (xsd:integer(SUBSTR(STR(?date), 1, 4)) AS ?year) WHERE {
  ?competition wdt:P1342 wd:Q111830 ;
             rdfs:label ?compLabel ;
             wdt:P585 ?date .
  FILTER (LANG(?compLabel) = 'en') .
  FILTER (CONTAINS(LCASE(STR(?compLabel)), 'pre-season')) .
  BIND(xsd:integer(SUBSTR(STR(?date), 1, 4)) AS ?yearNum) .
  FILTER (?yearNum >= 1988 && ?yearNum <= 2013) .
} ORDER BY DESC(?yearNum) LIMIT 1

